#[derive(Debug)]
struct Config {
    database_url: String,
    max_connections: u32,
    timeout_ms: u64,
    feature_flags: HashMap<String, bool>,
}

impl Config {
    fn new(database_url: &str) -> Self {
        let mut feature_flags = HashMap::new();
        feature_flags.insert("dark_mode".to_string(), true);
        feature_flags.insert("beta_features".to_string(), false);

        Config {
            database_url: database_url.to_string(),
            max_connections: 10,
            timeout_ms: 5000,
            feature_flags,
        }
    }
}

/// Leak config so it can be referenced globally with 'static lifetime.
/// This is appropriate because:
/// - Config is initialized once at startup
/// - It needs to be accessed from anywhere in the program
/// - The program's lifetime == config's lifetime, so no actual leak occurs
fn init_config(database_url: &str) -> &'static Config {
    let config = Box::new(Config::new(database_url));
    Box::leak(config)
}

